Hi @InhumanSoul!

If you're going to completely clear out the table and add new content, it would be better to destroy the instance of tablesorter, then reinitialize it - [demo](http://jsfiddle.net/qkn6ye4o/8/).

```js
var table = [{C1: "Row 1", C2: "with", C3: "data", C4: "some"},
            {C1: "Row 2", C2: "with", C3: "data", C4: "more"},
            {C1: "Row 3", C2: "with", C3: "data", C4: "extra"}];

$(function() {
  var jTable = $("#myTable");
  jTable.append($("<thead></thead>"));
  jTable.append($("<tbody></tbody>"));
  tablesorterInit(jTable);

  $("#enableC4").on("change", refreshTable);
  refreshTable();
});

function refreshTable() {
  var columnNames = ["C1", "C2", "C3"];

  if ($("#enableC4").prop("checked")) {
    var columnNames = ["C1", "C2", "C4", "C3"];
  }

  populateTable($("#myTable"), table, columnNames);
}

function tablesorterInit(jTable) {
  jTable.tablesorter({
      theme: "blue",
      widgets: ["filter"]
    })
    .tablesorterPager({
      removeRows: false
    });
}

function populateTable(jTable, table, columnNames) {
  var tBody = jTable.find("tbody");
  var tHead = jTable.find("thead");

  // remove tablesorter, but leave the class names in place (`false` flag)
  jTable.trigger('destroy', false);

  //Populate header
  tHead.empty();
  var headerRow = $("<tr></tr>");
  columnNames.forEach(function(name) {
    headerRow.append($("<th></th>", {
      text: name,
      class: "filter-match"
    }));
  });
  tHead.append(headerRow);

  //Populate body
  tBody.empty();
  for (var i = 0; i < table.length; i++) {
    var rowElement = $("<tr></tr>");
    columnNames.forEach(function(name) {
      rowElement.append($("<td></td>").append(table[i][name]));
    });
    tBody.append(rowElement);
  }

	tablesorterInit(jTable);
}
```

