                l = 65536 + ((l & 1023) << 10) + (a.charCodeAt(++i) & 1023)
                result[counter++] = l >> 18 | 240
                result[counter++] = l >> 12 & 63 | 128
            } else {
                result[counter++] = l >> 12 | 224
                result[counter++] = l >> 6 & 63 | 128
            }
        }
        
