I sketched out the tricky bit on the Jupyter JS side. Below code enables fullscreen tracking mode & disables it. You can try in the console of a notebook by changing the `id` var:

```
(function () {

    /** specific to jupyter **/
    
    var id = '16f0d1c0-5352-4e41-9b82-67ed83bece53';
    var $iframe = $('#' + id);
    var $cell = $iframe.parents('.cell');
    var $doc = $(window);    

    var orig = {
        iframe: {height: $iframe.height()}
    };

    var left;
    var listener = function () {
        left -= $cell.offset().left;
        $cell.css({width: $doc.width(), left: left});
        $iframe.css({height: $doc.height()})
    };

    window.commands =  {
        enableResizing: function () {
            $cell.css({position:'relative'});
            $cell.css({left: 0});
            left = 0;
            $(window).on('resize', listener);
            listener();
        },
        disableResizing: function () {
            $cell.css({position: 'static', width: '100%'})
            $iframe.css({height: orig.iframe.height});
            $(window).off('resize', listener);
        }
    };

    window.commands.enableResizing();

}());

```

